```class Solution {
public:
    long long maximumOr(vector<int>& nums, int k) {
        long long res = 0, max_val = 0;
        for (int num : nums) {
            res |= num;
            max_val = max(max_val, num);
        }
        k = min(k, (int)log2(max_val) + 1);
        for (int i = 0; i < k; i++) {
            res |= max_val;
            max_val <<= 1;
        }
        return res;
    }
};```
